import { Table,Button ,Modal,Tree} from 'antd'
import axios from 'axios'
import React, { useEffect, useState } from 'react'
import {DeleteOutlined,EditOutlined,ExclamationCircleFilled} from '@ant-design/icons'
const { confirm } = Modal;

export default function RoleList() {
  const [dataSource,setdataSource] = useState([])
  const [isModalOpen,setisModalOpen] = useState(false)
  const [rightList,setrightList] = useState([])
  const [currentRights,setcurrentRight] = useState([])
  const [currentId,setcurrentId] = useState(0)
  const confirmMethod = (item)=> {
    confirm({
      title: '你确定删除吗?',
      icon: <ExclamationCircleFilled />,
      //content: 'Some descriptions',
      onOk() {
        //console.log('OK');
        deleteMethod(item)
      },
      onCancel() {
        //console.log('Cancel');
      },
    });
  }
  const deleteMethod = (item)=>{
     
    axios.delete(`/api/rolelist?id=${item.id}`).then((res)=>{
      setdataSource(dataSource.filter(data=>data.id!==item.id))
    })
  }
  const columns = [
    {
      title: 'ID',
      dataIndex: 'id',
      render: (id)=>{
        return <b>{id}</b>
      }
    },
    {
      title: '角色名称',
      dataIndex: 'roleName',
    },
    {
      title: '操作',
      render:(item)=>{
        return <div>
          <Button  danger shape='circle' icon={<DeleteOutlined/>}
              onClick = {()=>confirmMethod(item)}
          ></Button>
          
          <Button  type='primary'shape='circle' icon={<EditOutlined/>}
            onClick = {()=>{
              setisModalOpen(true)
              setcurrentRight(item.rights)
              
              setcurrentId(item.id)
            }}
          ></Button>
          
          
        </div>
      }
    },
  ]
  useEffect(()=>{
    axios.get('/api/rolelist').then(res=>{
   
    let rolelist = []
    for(let i = 0; i < 3; i++) {
      let rights1 = res.data[i].rights;
      let rights2 = rights1.split(',\n')
      
      let list = {
        ...res.data[i],
        rights:rights2
      }
      
      rolelist.push(list);
      
    }
   
    setdataSource(rolelist);
    
   
    })
  },[])

  useEffect(()=>{
  Promise.all([
              axios.get('/api/rightlist'),
              axios.get('/api/rightlistchildren'),
      ]).then(res=>{
                
              
               let list1= res[0].data.map((item)=>{
                let temp = item.rightKey;
                delete item.rightKey
                return (
                  {...item,
                   'children':res[1].data.filter(data=>data.rightId === item.id),
                   'key':temp
                 })
               }
                )
              

                setrightList(list1)
   
        })

               }
,[])
  const handleOk = ()=>{
    setisModalOpen(false)
    //同步dataSoure
    setdataSource(dataSource.map(item=>{
      if(item.id === currentId) {
     
        return {
          ...item,
          'rights':currentRights
        }
      }
      return item
    }))
    
    axios.patch(`http://localhost:5000/roles/${currentId}`,{
      rights:currentRights
    })
  }
  const handleCancel = ()=>{
    setisModalOpen(false)
  }
  const onCheck = (checkKeys)=>{
  
    setcurrentRight(checkKeys.checked)
  }
  return (
    <div>
      <Table dataSource={dataSource} columns={columns}
      rowKey={(item)=>item.id}></Table>
      <Modal title="权限分配" open={isModalOpen} onOk={handleOk} onCancel={handleCancel}>
      <Tree
      checkable
      checkedKeys={currentRights}
      onCheck={onCheck}
      treeData={rightList}
      checkStrictly={true}
    />
      </Modal>
    </div>
  )
}
